'use client';

import React, {
  Children,
  isValidElement,
  memo,
  ReactElement,
  ReactNode,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState
} from 'react';
import { clsx } from '../../../helpers';
import { RuleType, SyntheticBaseEvent } from '../../../types';
import { flattenChildren } from '../../../helpers/flatten';
import {
  FieldInstancesRef,
  FormItemChildComponentProps,
  FormItemProps
} from '../../../types/form';
import { OptionProps } from '../../../types/select';
import { prefixClsFormItem } from '../../../utils';
import { FormContext } from '../Form';
import './style.css';
import { useWatch } from '@/hooks/useWatch';

const FormItem = memo(({
  prefixCls = prefixClsFormItem,
  name,
  label,
  rules = [],
  children,
  className = '',
  layout = 'vertical',
  style = {},
  extra,
  hideLabel = false,
  removeErrorMessageHeight = false,
  ...props
}: FormItemProps) => {
  const formContext = useContext(FormContext);

  const errorRef = useRef<HTMLSpanElement>(null);
  const fieldRef = useRef<FieldInstancesRef | null>(null);

  if (!formContext) {
    throw new Error('FormItem must be used within a Form');
  }

  const {
    isReseting,
    registerField,
    getFieldInstance,
    setFieldInstance,
    getFieldError,
    subscribeToFieldError
  } = formContext;

  const [errors, setErrors] = useState(getFieldError(name)?.[0]);

  const childrenList = useMemo(() => flattenChildren(children), [children]);

  useEffect(() => {
    if (name && !getFieldInstance(name)) {
      registerField(name, rules);
    }
  }, [name, rules]);

  useEffect(() => {
    setFieldInstance(name, fieldRef.current);
  }, [name, fieldRef.current])

  useEffect(() => () => registerField(name, undefined, true), [name])

  useEffect(() => {
    const unsubscribe = subscribeToFieldError(name, (errors) => {
      setErrors(errors?.[0]);
    })

    return () => {
      unsubscribe?.()
    }
  }, [name]);

  const isRequired = useMemo(
    () => rules.some((rule: RuleType) => rule.required),
    [rules]
  );

  return (
    <div
      style={style}
      data-instance={name}
      className={clsx([
        `${prefixCls}`,
        {
          [layout]: layout,
          [className]: className,
          noStyle: props.noStyle
        }
      ])}
    >
      {!props.noStyle && (label || name) && !hideLabel && (
        <label className={`${prefixCls}-label`} htmlFor={name}>
          {label || name}
          {isRequired && <span className={`${prefixCls}-required`}>*</span>}
          {/* @Todo need to add Tooltip like Ant design */}
        </label>
      )}

      {Children.map(childrenList, (child, key) => {
        if (isValidElement(child)) {
          return (
            <div>
              <FormItemChildComponent
                {...props}
                key={`${key}_${name}_${isReseting}`}
                // eslint-disable-next-line @typescript-eslint/ban-ts-comment
                // @ts-expect-error
                ref={fieldRef}
                name={name}
                child={child}
                error={!!errors}
              />

              {extra
                ? <div className={`${prefixCls}-extra`}>
                  {extra || ''}
                </div>
                : null}

              {!props.noStyle && (
                <span
                  ref={errorRef}
                  className={clsx([
                    `${prefixCls}-error`,
                    { [`${prefixCls}-has-error`]: errors?.length }
                  ])}
                  style={{
                    ...removeErrorMessageHeight ? { minHeight: 0 } : {},
                    ...extra ? { marginBottom: 0 } : {}
                  }}
                >
                  {errors || ''}
                </span>
              )}
            </div>
          )
        }

        return child;
      })}
    </div>
  );
});

const FormItemChildComponent = memo(({
  child,
  name,
  error,
  initialValue,
  normalize,
  noStyle,
  ref,
  dependencies = [],
  ...props
}: FormItemChildComponentProps) => {
  const formContext = useContext(FormContext);
  const _formFieldValue = useWatch({ name })

  const [wasNormalize, setWasNormalize] = useState(false);

  const {
    getFieldsValue,
    setFieldValue,
    subscribeToFields,
    validateFields
  } = formContext || {};

  // eslint-disable-next-line @typescript-eslint/ban-ts-comment
  // @ts-expect-error
  const { onChange, value } = child.props;
  const fieldValue = useMemo(
    () => value ?? _formFieldValue ?? initialValue,
    [value, _formFieldValue, initialValue]
  );

  useEffect(() => {
    if (initialValue) {
      setFieldValue?.(name, initialValue);
    }
  }, [name]);

  useEffect(() => {
    if (name && dependencies.length > 0) {
      const unsubscribe = subscribeToFields?.(dependencies, () => {
        validateFields?.([name]);
      });

      return () => {
        unsubscribe?.();
      };
    }
  }, [dependencies, name]);

  const handleChange = (e: SyntheticBaseEvent, option?: OptionProps) => {
    let rawValue: RuleType | SyntheticBaseEvent = e?.target
      ? e.target.value
      : e;

    if (normalize) {
      const prevValue = fieldValue;
      const allValues = getFieldsValue?.();

      rawValue = normalize(rawValue, prevValue, allValues);

      if (rawValue === prevValue) {
        e.target.value = rawValue;
        setWasNormalize(prev => !prev);

        const timeout = setTimeout(() => {
          (
            document.querySelector(`[name='${name}']`) as HTMLInputElement
          )?.focus();

          clearTimeout(timeout);
        }, 0);

        return;
      }
    }

    setFieldValue?.(name, rawValue, undefined, undefined, true);
    onChange?.(e, option);
  };

  const injectPropsIntoFinalLeaf = useCallback((child: ReactNode): ReactNode => {
    if (!isValidElement(child)) {
      return child;
    }

    const childProps = child.props as ReactElement & {
      children: ReactElement[],
      __injected: boolean
    }

    const isWrapper =
      typeof child.type === 'string' &&
      !('dangerouslySetInnerHTML' in childProps) &&
      ['div', 'span', 'label'].includes(child.type);

    if (isWrapper) {
      return (
        <child.type {...childProps}>
          {Children.map(flattenChildren(childProps.children), injectPropsIntoFinalLeaf)}
        </child.type>
      )
    }

    if (childProps?.__injected) {
      return child;
    }

    return <child.type
      {...props}
      ref={ref}
      name={name}
      // eslint-disable-next-line @typescript-eslint/ban-ts-comment
      // @ts-expect-error
      {...child.props}
      // eslint-disable-next-line @typescript-eslint/ban-ts-comment
      // @ts-expect-error
      size={childProps.size || props.size}
      child={child}
      value={fieldValue}
      onChange={handleChange}
      key={`${name}_${wasNormalize}`}
      {...('dangerouslySetInnerHTML' in childProps ? {} : {
        __injected: true,
        ...(error ? { error } : {}),
      })
      }
    />
  }, [
    name,
    fieldValue,
    wasNormalize,
    error,
    handleChange,
    props,
    ref
  ]);

  return injectPropsIntoFinalLeaf(child)
});

FormItem.displayName = 'FormItem';

export default FormItem;